namespace sv_4b8ca7e61edf472aac15f4099b5665c4.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_4b8ca7e61edf472aac15f4099b5665c4.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="catalog-container d-flex">
    @* ──── Left Sidebar (Filters) ──── *@
    <aside class="catalog-sidebar">
        <h5>Filters</h5>

        @* Category checkboxes *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Category</label>
            @if (categories is not null)
            {
                @foreach (var cat in categories)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                               checked="@selectedCategories.Contains(cat)"
                               @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                    </div>
                }
            }
            else
            {
                <p class="text-muted small">Loading categories…</p>
            }
        </div>

        @* Price range *@
        <div class="mb-3">
            <label class="form-label fw-semibold">Price Range</label>
            <div class="d-flex gap-2">
                <input type="number" class="form-control form-control-sm" placeholder="Min"
                       @bind="minPrice" @bind:event="oninput" min="0" />
                <input type="number" class="form-control form-control-sm" placeholder="Max"
                       @bind="maxPrice" @bind:event="oninput" min="0" />
            </div>
        </div>

        @* In Stock Only *@
        <div class="form-check mb-3">
            <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>

        @* Action buttons *@
        <div class="d-grid gap-2">
            <button class="btn btn-primary btn-sm" @onclick="ApplyFilters" disabled="@isLoading">
                Apply Filters
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters" disabled="@isLoading">
                Clear Filters
            </button>
        </div>
    </aside>

    @* ──── Main Content ──── *@
    <div class="catalog-main">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-link p-0 ms-2" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
                <span class="ms-3">Loading products…</span>
            </div>
        }
        else if (searchResult is not null)
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 fw-semibold" for="sortBy">Sort by:</label>
                    <select class="form-select form-select-sm w-auto" id="sortBy"
                            @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    @if (searchResult.TotalCount > 0)
                    {
                        var start = (searchResult.Page - 1) * searchResult.PageSize + 1;
                        var end = Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount);
                        <text>Showing @start–@end of @searchResult.TotalCount products</text>
                    }
                    else
                    {
                        <text>No products found</text>
                    }
                </span>
            </div>

            @if (searchResult.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <h5 class="text-muted">No products match your filters</h5>
                    <p class="text-muted">Try adjusting your filters or clearing them.</p>
                    <button class="btn btn-outline-primary btn-sm" @onclick="ClearFilters">
                        Clear Filters
                    </button>
                </div>
            }
            else
            {
                @* Product Grid *@
                <div class="product-grid">
                    @foreach (var product in searchResult.Items)
                    {
                        <div class="card product-card" @onclick="() => OnProductClicked(product.Id)"
                             role="button" tabindex="0">
                            <div class="product-image-placeholder" title="@product.Name">
                                <span>@product.Name</span>
                            </div>
                            <div class="card-body">
                                <h6 class="card-title text-truncate" title="@product.Name">@product.Name</h6>
                                <p class="card-text fw-bold mb-1">@product.Price.ToString("C")</p>
                                <div class="mb-1" title="@($"{product.Rating:F1} out of 5")">
                                    @((MarkupString)GetStarRating(product.Rating))
                                </div>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <button class="btn btn-sm btn-success w-100 mt-auto"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => AddToCart(product)"
                                        @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    }
                </div>

                @* Pagination *@
                @if (totalPages > 1)
                {
                    <nav aria-label="Product pagination" class="mt-4">
                        <ul class="pagination justify-content-center flex-wrap">
                            <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                        disabled="@(currentPage == 1)">
                                    Previous
                                </button>
                            </li>
                            @foreach (var p in GetPageNumbers())
                            {
                                <li class="page-item @(p == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                                </li>
                            }
                            <li class="page-item @(currentPage == totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                        disabled="@(currentPage == totalPages)">
                                    Next
                                </button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        }
    </div>
</div>

@code {
    /// <summary>
    /// Raised when a product card is clicked so a parent can navigate to the detail page.
    /// </summary>
    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    // ── Filter state ──
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    // ── Search state ──
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private PagedResult<Product>? searchResult;
    private int totalPages;

    // ── UI state ──
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialDataAsync();
    }

    private async Task LoadInitialDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            // Load categories and first page in parallel
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = PerformSearchCoreAsync();

            categories = await categoriesTask;
            searchResult = await searchTask;

            UpdateTotalPages();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task<PagedResult<Product>> PerformSearchCoreAsync()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );

        return await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
    }

    private async Task PerformSearchAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            searchResult = await PerformSearchCoreAsync();
            UpdateTotalPages();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void UpdateTotalPages()
    {
        if (searchResult is not null && searchResult.PageSize > 0)
        {
            totalPages = (int)Math.Ceiling((double)searchResult.TotalCount / searchResult.PageSize);
        }
        else
        {
            totalPages = 1;
        }
    }

    // ── Filter handlers ──

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await PerformSearchAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        sortBy = "price_asc";
        await PerformSearchAsync();
    }

    // ── Sort handler ──

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await PerformSearchAsync();
    }

    // ── Pagination ──

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages || page == currentPage)
            return;

        currentPage = page;
        await PerformSearchAsync();
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;

        if (totalPages <= maxVisible)
            return Enumerable.Range(1, totalPages);

        var start = Math.Max(1, currentPage - maxVisible / 2);
        var end = Math.Min(totalPages, start + maxVisible - 1);
        if (end - start + 1 < maxVisible)
            start = Math.Max(1, end - maxVisible + 1);

        return Enumerable.Range(start, end - start + 1);
    }

    // ── Product interactions ──

    private async Task OnProductClicked(int productId)
    {
        await OnProductSelected.InvokeAsync(productId);
    }

    private void AddToCart(Product product)
    {
        // Placeholder for cart integration
    }

    // ── Retry ──

    private async Task RetryLoad()
    {
        await LoadInitialDataAsync();
    }

    // ── Helpers ──

    private static string GetStarRating(double rating)
    {
        var rounded = (int)Math.Round(rating);
        var filled = new string('★', Math.Min(rounded, 5));
        var empty = new string('☆', 5 - Math.Min(rounded, 5));
        return $"<span class=\"star-rating\">{filled}{empty}</span>";
    }
}

.catalog-container {
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
    padding: 1rem;
    background-color: #f8f9fa;
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
    align-self: flex-start;
    position: sticky;
    top: 1rem;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.2s, transform 0.15s;
    display: flex;
    flex-direction: column;
    height: 100%;
}

.product-card:hover {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
    transform: translateY(-2px);
}

.product-card .card-body {
    display: flex;
    flex-direction: column;
    flex: 1;
}

.product-image-placeholder {
    background: linear-gradient(135deg, #e9ecef 0%, #ced4da 100%);
    height: 160px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.85rem;
    text-align: center;
    padding: 1rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .star-rating {
    color: #ffc107;
    font-size: 1rem;
    letter-spacing: 1px;
}

@media (max-width: 768px) {
    .catalog-container {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: 1 1 auto;
        max-width: 100%;
        position: static;
    }

    .product-grid {
        grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
    }
}

